#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char S[1000001];
        scanf("%s", S);
        int n = strlen(S);
        int count = 0;
        for (int i = 0; i < n; i++) {
            for (int j = i; j < n; j++) {
                int sum = 0;
                int flag = 1;
                for (int k = i; k <= j; k++) {
                    if (S[k] != S[j - k + i]) {
                        flag = 0;
                        break;
                    }
                    sum += S[k] - '0';
                }
                if (flag && (i == j || S[i] != '0') && sum % 3 == 0) {
                    count++;
                }
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

