        scanner.nextLine();
        while (T-- > 0) {
            String S = scanner.nextLine();
            int n = S.length();
            int count = 0;
            for (int i = 0; i < n; i++) {
                for (int j = i; j < n; j++) {
                    int sum = 0;
                    boolean flag = true;
                    for (int k = i; k <= j; k++) {
                        if (S.charAt(k) != S.charAt(j - k + i)) {
                            flag = false;
                            break;
                        }
                        sum += S.charAt(k) - '0';
                    }
                    if (flag && (i == j || S.charAt(i) != '0') && sum % 3 == 0) {
                        count++;
                    }
                }
            }
            System.out.println(count);
