import sys

def count_palindromes(S):
    n = len(S)
    count = 0
    for i in range(n):
        for j in range(i, n):
            substring = S[i:j+1]
            if substring == substring[::-1] and (i == j or substring[0] != '0') and sum(int(digit) for digit in substring) % 3 == 0:
                count += 1
    return count

T = int(sys.stdin.readline())
for _ in range(T):
    S = sys.stdin.readline().strip()
    print(count_palindromes(S))

